Descripción del error:
{{ $json.execution.error.message }}

parameters.jsCode:
// Check if there are existing open tasks for this workflow error
const checkResult = $('Buscar Tarea Existente').item.json;
const errorData = $('Error Trigger').item.json;

// Get the array of existing issues
const existingIssues = checkResult.data || checkResult || [];
const workflowName = errorData.workflow ? errorData.workflow.name : 'Unknown';

// Filter to find tasks that match this specific workflow
const matchingTasks = (Array.isArray(existingIssues) ? existingIssues : []).filter(issue => {
  return issue.title && issue.title.includes(workflowName);
});

if (matchingTasks.length > 0) {
  // Found existing task - return it for comment-only path
  return [{
    json: {
      action: 'comment',
      existingTaskId: matchingTasks[0].id,
      existingTaskIdentifier: matchingTasks[0].identifier,
      workflowName: workflowName,
      errorMessage: errorData.execution && errorData.execution.error ? errorData.execution.error.message : 'Sin mensaje',
      executionId: errorData.execution ? errorData.execution.id : 'N/A',
      executionUrl: errorData.execution ? errorData.execution.url : 'N/A'
    }
  }];
} else {
  // No existing task - return for create path
  return [{
    json: {
      action: 'create',
      workflowName: workflowName,
      workflowId: errorData.workflow ? errorData.workflow.id : 'N/A',
      errorMessage: errorData.execution && errorData.execution.error ? errorData.execution.error.message : 'Sin mensaje',
      executionId: errorData.execution ? errorData.execution.id : 'N/A',
      executionUrl: errorData.execution ? errorData.execution.url : 'N/A'
    }
  }];
}

